import React, { useState } from "react";
import { BrowserRouter, Routes, Route, NavLink, useLocation } from "react-router-dom";
import { DataProvider, useData } from "./lib/DataContext";
import Dashboard from "./pages/Dashboard";
import WorkOrders from "./pages/WorkOrders";
import Equipment from "./pages/Equipment";
import TimeTracking from "./pages/TimeTracking";
import Reports from "./pages/Reports";
import {
  LayoutDashboard, ClipboardList, Wrench,
  Timer, BarChart2, Settings
} from "lucide-react";
import "./index.css";

const NAV = [
  { to: "/",          icon: LayoutDashboard, label: "Dashboard" },
  { to: "/orders",    icon: ClipboardList,   label: "Órdenes" },
  { to: "/equipment", icon: Wrench,          label: "Equipos" },
  { to: "/time",      icon: Timer,           label: "Tiempo" },
  { to: "/reports",   icon: BarChart2,       label: "Reportes" },
];

function Shell({ children }) {
  const { isDemo } = useData();
  const location   = useLocation();

  return (
    <div className="app-shell">
      {/* Topbar */}
      <header className="topbar">
        <div className="topbar-logo">
          <Wrench size={20} />
          MechTrack
        </div>
        <span className="topbar-tag">v1.0</span>
        {isDemo && <span className="topbar-demo-badge">MODO DEMO</span>}
        <div className="topbar-spacer" />
        <div className="topbar-user">
          <div className="topbar-avatar">MT</div>
          <span style={{ fontSize: 13, color: "var(--text2)" }}>
            {isDemo ? "Demo User" : "Mi Taller"}
          </span>
        </div>
      </header>

      {/* Desktop sidebar */}
      <aside className="sidebar">
        <div className="sidebar-section">Navegación</div>
        {NAV.map(({ to, icon: Icon, label }) => (
          <NavLink key={to} to={to} end={to === "/"} className={({ isActive }) => `nav-link${isActive ? " active" : ""}`}>
            <Icon size={16} />
            {label}
          </NavLink>
        ))}
        <div className="sidebar-section" style={{ marginTop: "auto" }}>Sistema</div>
        <NavLink to="/settings" className={({ isActive }) => `nav-link${isActive ? " active" : ""}`}>
          <Settings size={16} /> Configuración
        </NavLink>
      </aside>

      {/* Page */}
      <main className="main-content">
        {children}
      </main>

      {/* Mobile bottom nav */}
      <nav className="mobile-nav">
        {NAV.map(({ to, icon: Icon, label }) => (
          <NavLink key={to} to={to} end={to === "/"} className={({ isActive }) => isActive ? "active" : ""}>
            <Icon size={20} />
            {label}
          </NavLink>
        ))}
      </nav>
    </div>
  );
}

export default function App() {
  return (
    <DataProvider>
      <BrowserRouter>
        <Routes>
          <Route path="/*" element={
            <Shell>
              <Routes>
                <Route path="/"          element={<Dashboard />} />
                <Route path="/orders"    element={<WorkOrders />} />
                <Route path="/equipment" element={<Equipment />} />
                <Route path="/time"      element={<TimeTracking />} />
                <Route path="/reports"   element={<Reports />} />
                <Route path="/settings"  element={<SettingsPage />} />
              </Routes>
            </Shell>
          } />
        </Routes>
      </BrowserRouter>
    </DataProvider>
  );
}

function SettingsPage() {
  return (
    <div>
      <div className="page-header">
        <div>
          <h1 className="page-title">Configuración</h1>
          <p className="page-subtitle">Conecta tu Google Sheet</p>
        </div>
      </div>
      <div className="card" style={{ maxWidth: 600 }}>
        <div className="card-header">
          <span className="card-title">Google Sheets API</span>
        </div>
        <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
          <p style={{ fontSize: 13, color: "var(--text2)", lineHeight: 1.7 }}>
            Para conectar tu hoja de cálculo, crea un archivo <code style={{ fontFamily: "var(--font-mono)", background: "var(--bg3)", padding: "2px 6px", borderRadius: 3 }}>.env</code> en la raíz del proyecto con estas variables:
          </p>
          <pre style={{ background: "var(--bg3)", padding: 16, borderRadius: 6, fontSize: 12, fontFamily: "var(--font-mono)", color: "var(--accent)", overflowX: "auto" }}>
{`REACT_APP_SPREADSHEET_ID=tu_spreadsheet_id
REACT_APP_GOOGLE_API_KEY=tu_api_key
REACT_APP_GOOGLE_CLIENT_ID=tu_client_id`}
          </pre>
          <div style={{ background: "rgba(74,158,255,0.08)", border: "1px solid rgba(74,158,255,0.2)", borderRadius: 6, padding: 14, fontSize: 13, color: "var(--info)" }}>
            <strong>Tabs requeridas en tu Sheet:</strong> Mechanics · Equipment · WorkOrders · TimeEntries
          </div>
          <a
            href="https://developers.google.com/sheets/api/quickstart/js"
            target="_blank" rel="noreferrer"
            className="btn btn-ghost btn-sm"
            style={{ alignSelf: "flex-start" }}
          >
            Ver documentación de Google Sheets API →
          </a>
        </div>
      </div>
    </div>
  );
}
